def count_range_sum(nums: list[int], lower: int, upper: int) -> int:
    n = len(nums)
    prefix_sums = [0] * (n + 1)
    for i in range(n):
        prefix_sums[i+1] = prefix_sums[i] + nums[i]

    def merge_sort_count(left, right):
        if right - left <= 1:
            return 0

        mid = (left + right) // 2
        count = merge_sort_count(left, mid) + merge_sort_count(mid, right)

        left_ptr = left
        right_ptr = left
        for k in range(mid, right):
            target_low = prefix_sums[k] - upper
            target_high = prefix_sums[k] - lower

            while left_ptr < mid and prefix_sums[left_ptr] < target_low:
                left_ptr += 1
            while right_ptr < mid and prefix_sums[right_ptr] <= target_high:
                right_ptr += 1

            count += right_ptr - left_ptr

        sorted_arr = []
        i, j = left, mid
        while i < mid and j < right:
            if prefix_sums[i] <= prefix_sums[j]:
                sorted_arr.append(prefix_sums[i])
                i += 1
            else:
                sorted_arr.append(prefix_sums[j])
                j += 1
        sorted_arr.extend(prefix_sums[i:mid])
        sorted_arr.extend(prefix_sums[j:right])
        prefix_sums[left:right] = sorted_arr

        return count

    return merge_sort_count(0, n + 1)
