def matrix_mult(A, B, mod=None):
    res = [
        [A[0][0]*B[0][0] + A[0][1]*B[1][0], A[0][0]*B[0][1] + A[0][1]*B[1][1]],
        [A[1][0]*B[0][0] + A[1][1]*B[1][0], A[1][0]*B[0][1] + A[1][1]*B[1][1]]
    ]
    if mod is not None:
        res = [[x % mod for x in row] for row in res]
    return res

def matrix_power(M, n, mod=None):
    if n == 0:
        return [[1, 0], [0, 1]]
    result = [[1, 0], [0, 1]]
    base = M
    while n > 0:
        if n % 2 == 1:
            result = matrix_mult(result, base, mod)
        base = matrix_mult(base, base, mod)
        n //= 2
    return result

def fibonacci(n):
    if n == 0:
        return 0
    M = [[1, 1], [1, 0]]
    res = matrix_power(M, n)
    return res[0][1]

def pisano_period(m):
    if m == 1:
        return 1
    M = [[1, 1], [1, 0]]
    curr = [[1, 0], [0, 1]]
    for k in range(1, 6 * m + 1):
        curr = matrix_mult(curr, M, m)
        if curr[0][1] % m == 0 and curr[0][0] % m == 1:
            return k
    return -1
