import json

class TreeNode:
    def __init__(self, val="", left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def serialize(root) -> str:
    """Encode tree to string."""
    if root is None:
        return ""

    res = []
    stack = [root]
    while stack:
        node = stack.pop()
        if node is None:
            res.append("__NULL__")
        else:
            res.append(json.dumps(node.val))
            stack.append(node.right)
            stack.append(node.left)

    return "\x00".join(res)

def deserialize(data) -> 'TreeNode | None':
    """Decode string to tree."""
    if not data:
        return None

    tokens = data.split("\x00")
    if tokens[0] == "__NULL__":
        return None

    root = TreeNode(json.loads(tokens[0]))
    stack = [root]
    i = 1
    n = len(tokens)

    while i < n:
        val = tokens[i]
        i += 1
        node = None if val == "__NULL__" else TreeNode(json.loads(val))

        while stack and stack[-1].left is not None and stack[-1].right is not None:
            stack.pop()

        if not stack:
            break

        parent = stack[-1]
        if parent.left is None:
            parent.left = node
        else:
            parent.right = node

        if node is not None:
            stack.append(node)

    return root
