class DirectedGraph:
    def __init__(self, n: int):
        self.n = n
        self.adj = [[] for _ in range(n)]
        self.in_degree = [0] * n

    def add_edge(self, u: int, v: int) -> None:
        if v not in self.adj[u]:
            self.adj[u].append(v)
            self.in_degree[v] += 1

    def has_cycle(self) -> bool:
        indeg = list(self.in_degree)
        queue = [i for i in range(self.n) if indeg[i] == 0]
        count = 0
        while queue:
            u = queue.pop(0)
            count += 1
            for v in self.adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    queue.append(v)
        return count != self.n

    def topological_sort(self) -> list[int] | None:
        if self.has_cycle():
            return None
        indeg = list(self.in_degree)
        queue = [i for i in range(self.n) if indeg[i] == 0]
        queue.sort()
        result = []
        while queue:
            u = queue.pop(0)
            result.append(u)
            for v in self.adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    queue.append(v)
            queue.sort()
        return result

    def all_topological_sorts(self) -> list[list[int]]:
        if self.has_cycle():
            return []
        indeg = list(self.in_degree)
        result = []
        current = []

        def backtrack():
            if len(current) == self.n:
                result.append(list(current))
                return
            for i in range(self.n):
                if indeg[i] == 0 and i not in current:
                    # Choose i
                    current.append(i)
                    indeg[i] -= 1
                    for v in self.adj[i]:
                        indeg[v] -= 1
                    backtrack()
                    # Undo
                    for v in self.adj[i]:
                        indeg[v] += 1
                    indeg[i] += 1
                    current.pop()

        backtrack()
        result.sort()
        return result

    def longest_path(self) -> int:
        if self.has_cycle():
            return -1
        indeg = list(self.in_degree)
        # Topological order
        queue = [i for i in range(self.n) if indeg[i] == 0]
        topo = []
        temp_indeg = list(indeg)
        while queue:
            u = queue.pop(0)
            topo.append(u)
            for v in self.adj[u]:
                temp_indeg[v] -= 1
                if temp_indeg[v] == 0:
                    queue.append(v)
        # DP for longest path
        dist = [0] * self.n
        for u in topo:
            for v in self.adj[u]:
                if dist[u] + 1 > dist[v]:
                    dist[v] = dist[u] + 1
        return max(dist) if self.n > 0 else 0
