from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self.events: list[Event] = []

    def _overlaps(self, e1: Event, e2: Event) -> bool:
        return e1.start < e2.end and e1.end > e2.start

    def _trim_event(self, event: Event, conflicts: list[Event]) -> list[Event]:
        """Trim event around conflicts, returning non-overlapping fragments."""
        fragments = []
        current_start = event.start
        current_end = event.end

        # Sort conflicts by start time to process sequentially
        sorted_conflicts = sorted(conflicts, key=lambda e: e.start)

        for conflict in sorted_conflicts:
            if current_start >= current_end:
                break

            # If conflict starts after current fragment ends, no need to check further for this fragment
            if conflict.start >= current_end:
                break

            # If conflict ends before current fragment starts, skip
            if conflict.end <= current_start:
                continue

            # Overlap exists
            if conflict.start > current_start:
                # Add fragment before conflict
                fragments.append(Event(current_start, conflict.start, event.title, event.priority))
                current_start = conflict.end
            else:
                # Conflict starts before or at current_start
                current_start = max(current_start, conflict.end)

        if current_start < current_end:
            fragments.append(Event(current_start, current_end, event.title, event.priority))

        return fragments

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("Start time must be less than end time.")

        conflicts = [e for e in self.events if self._overlaps(e, event)]

        if not conflicts:
            self.events.append(event)
            self.events.sort(key=lambda e: e.start)
            return [event]

        max_conflict_priority = max(e.priority for e in conflicts)

        if event.priority > max_conflict_priority:
            # New event has higher priority
            removed_events = []
            new_fragments = []

            # Remove conflicting events and create fragments
            for e in conflicts:
                removed_events.append(e)
                # Split e around event
                if e.start < event.start:
                    new_fragments.append(Event(e.start, event.start, e.title, e.priority))
                if e.end > event.end:
                    new_fragments.append(Event(event.end, e.end, e.title, e.priority))

            # Remove conflicts from calendar
            for e in conflicts:
                self.events.remove(e)

            # Add new event and fragments
            self.events.append(event)
            self.events.extend(new_fragments)
            self.events.sort(key=lambda e: e.start)

            # Return modified/removed events (the old ones and the new fragments)
            return removed_events + new_fragments
        else:
            # New event has equal or lower priority
            fragments = self._trim_event(event, conflicts)
            self.events.extend(fragments)
            self.events.sort(key=lambda e: e.start)
            return fragments

    def get_events(self, start: float, end: float) -> list[Event]:
        result = []
        for e in self.events:
            if e.start < end and e.end > start:
                result.append(e)
        result.sort(key=lambda e: e.start)
        return result

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        events = self.get_events(start, end)
        slots = []
        current = start

        for e in events:
            if e.start > current:
                duration = e.start - current
                if duration >= min_duration:
                    slots.append((current, e.start))
            current = max(current, e.end)

        if end > current:
            duration = end - current
            if duration >= min_duration:
                slots.append((current, end))

        return slots

    def utilization(self, start: float, end: float) -> float:
        events = self.get_events(start, end)
        occupied = 0.0
        for e in events:
            overlap_start = max(e.start, start)
            overlap_end = min(e.end, end)
            if overlap_end > overlap_start:
                occupied += overlap_end - overlap_start

        total_duration = end - start
        if total_duration == 0:
            return 0.0
        return occupied / total_duration
