def regex_match(pattern: str, text: str) -> bool:
    class Node: pass
    class Char(Node):
        def __init__(self, c): self.c = c
    class Dot(Node): pass
    class CharClass(Node):
        def __init__(self, chars, negated): self.chars = chars; self.negated = negated
    class Group(Node):
        def __init__(self, node): self.node = node
    class Seq(Node):
        def __init__(self, nodes): self.nodes = nodes
    class Alt(Node):
        def __init__(self, left, right): self.left = left; self.right = right
    class Star(Node):
        def __init__(self, node): self.node = node
    class Plus(Node):
        def __init__(self, node): self.node = node
    class Question(Node):
        def __init__(self, node): self.node = node

    def parse(pattern):
        pos = [0]
        def peek():
            return pattern[pos[0]] if pos[0] < len(pattern) else None
        def advance():
            c = pattern[pos[0]]; pos[0] += 1; return c

        def parse_alt():
            nodes = [parse_concat()]
            while peek() == '|':
                advance()
                nodes.append(parse_concat())
            if len(nodes) == 1: return nodes[0]
            res = nodes[0]
            for n in nodes[1:]: res = Alt(res, n)
            return res

        def parse_concat():
            nodes = []
            while peek() not in (None, '|', ')'):
                nodes.append(parse_quant())
            if not nodes: return Char('') # Empty match
            if len(nodes) == 1: return nodes[0]
            return Seq(nodes)

        def parse_quant():
            node = parse_atom()
            q = peek()
            if q == '*': advance(); return Star(node)
            if q == '+': advance(); return Plus(node)
            if q == '?': advance(); return Question(node)
            return node

        def parse_atom():
            c = peek()
            if c == '.': advance(); return Dot()
            if c == '[': return parse_char_class()
            if c == '(':
                advance()
                node = parse_alt()
                if peek() == ')': advance()
                return Group(node)
            if c == '\\':
                advance()
                return Char(advance())
            advance()
            return Char(c)

        def parse_char_class():
            advance() # [
            negated = peek() == '^'
            if negated: advance()
            chars = set()
            if peek() == ']': chars.add(']'); advance()
            while peek() is not None and peek() != ']':
                c = advance()
                if peek() == '-' and pos[0] + 1 < len(pattern) and pattern[pos[0]+1] != ']':
                    advance() # -
                    end_c = advance()
                    for code in range(ord(c), ord(end_c)+1): chars.add(chr(code))
                else: chars.add(c)
            if peek() == ']': advance()
            return CharClass(chars, negated)

        return parse_alt()

    root = parse(pattern)

    def match(node, text, start):
        if isinstance(node, Char):
            if start < len(text) and text[start] == node.c: return {start + 1}
            return set()
        if isinstance(node, Dot):
            if start < len(text): return {start + 1}
            return set()
        if isinstance(node, CharClass):
            if start < len(text):
                c = text[start]
                if (c in node.chars) ^ node.negated: return {start + 1}
            return set()
        if isinstance(node, Group):
            return match(node.node, text, start)
        if isinstance(node, Seq):
            if not node.nodes: return {start}
            res = set()
            for mid in match(node.nodes[0], text, start):
                res |= match(Seq(node.nodes[1:]), text, mid)
            return res
        if isinstance(node, Alt):
            return match(node.left, text, start) | match(node.right, text, start)
        if isinstance(node, Star):
            res = {start}
            curr = start
            while True:
                nexts = match(node.node, text, curr)
                if not nexts: break
                new_ends = {n for n in nexts if n > curr}
                if not new_ends: break
                res |= new_ends
                curr = max(new_ends)
            return res
        if isinstance(node, Plus):
            nexts = match(node.node, text, start)
            if not nexts: return set()
            res = set(nexts)
            curr = max(nexts)
            while True:
                nexts = match(node.node, text, curr)
                if not nexts: break
                new_ends = {n for n in nexts if n > curr}
                if not new_ends: break
                res |= new_ends
                curr = max(new_ends)
            return res
        if isinstance(node, Question):
            return {start} | match(node.node, text, start)
        return {start}

    return len(text) in match(root, text, 0)
