import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self._hashes = []
        self._hash_to_node = {}
        self._node_to_hashes = {}

    def _md5_hash(self, key: str) -> str:
        return hashlib.md5(key.encode()).hexdigest()

    def add_node(self, node_id: str) -> None:
        if node_id in self._node_to_hashes:
            return
        hashes = []
        for i in range(self.num_virtual_nodes):
            vnode = f"{node_id}#v{i}"
            h = self._md5_hash(vnode)
            hashes.append(h)
            self._hash_to_node[h] = node_id
        hashes.sort()
        self._hashes.extend(hashes)
        self._hashes.sort()
        self._node_to_hashes[node_id] = hashes

    def remove_node(self, node_id: str) -> None:
        if node_id not in self._node_to_hashes:
            raise KeyError(node_id)
        node_hashes = self._node_to_hashes.pop(node_id)
        for h in node_hashes:
            del self._hash_to_node[h]
        self._hashes = [h for h in self._hashes if h not in node_hashes]

    def get_node(self, key: str) -> str | None:
        if not self._hashes:
            return None
        h = self._md5_hash(key)
        idx = bisect.bisect_right(self._hashes, h)
        if idx == len(self._hashes):
            idx = 0
        return self._hash_to_node[self._hashes[idx]]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self._hashes:
            return []
        h = self._md5_hash(key)
        idx = bisect.bisect_right(self._hashes, h)
        n = len(self._hashes)
        nodes = []
        seen = set()
        for i in range(n):
            actual_idx = (idx + i) % n
            node = self._hash_to_node[self._hashes[actual_idx]]
            if node not in seen:
                seen.add(node)
                nodes.append(node)
                if len(nodes) == num_replicas:
                    break
        return nodes
