import threading
import time
from collections import OrderedDict

class TTLCache:
    def __init__(self, max_size: int, ttl_seconds: float):
        self.max_size = max_size
        self.ttl_seconds = ttl_seconds
        self.cache = OrderedDict()
        self.lock = threading.Lock()

    def get(self, key: str):
        with self.lock:
            if key not in self.cache:
                return None
            value, expiry = self.cache[key]
            if time.monotonic() > expiry:
                del self.cache[key]
                return None
            self.cache.move_to_end(key)
            return value

    def put(self, key: str, value) -> None:
        with self.lock:
            current_time = time.monotonic()
            expiry = current_time + self.ttl_seconds
            if key in self.cache:
                self.cache[key] = (value, expiry)
                self.cache.move_to_end(key)
            else:
                if self.max_size > 0 and len(self.cache) >= self.max_size:
                    self.cache.popitem(last=False)
                self.cache[key] = (value, expiry)

    def cleanup(self) -> int:
        with self.lock:
            current_time = time.monotonic()
            expired_keys = [k for k, (v, exp) in self.cache.items() if current_time > exp]
            for k in expired_keys:
                del self.cache[k]
            return len(expired_keys)

    def size(self) -> int:
        with self.lock:
            current_time = time.monotonic()
            return sum(1 for _, (v, exp) in self.cache.items() if current_time <= exp)
